mapper.select:
/* CartMapper.countShopCartByGoodsIdAndSizeId: 쇼핑몰 장바구니의 동일 상품/사이즈 등록 건수 조회 */
SELECT COUNT(1)
  FROM CART
 WHERE CUST_NO = #{custNo}
   AND GOODS_ID = #{goodsId}
   AND SIZE_ID = #{sizeId}
   AND CART_GB_CD = 'C'

/* CartMapper.getShopCartIdByGoodsIdAndSizeId: 쇼핑몰 장바구니의 동일 상품/사이즈 장바구니번호 조회 */
SELECT CART_ID
  FROM CART
 WHERE CUST_NO = #{custNo}
   AND GOODS_ID = #{goodsId}
   AND SIZE_ID = #{sizeId}
   AND CART_GB_CD = 'C'
 ORDER BY REG_DT DESC, CART_ID DESC
 LIMIT 1

/* CartMapper.getShopCartDuplicateItemList: 쇼핑몰 장바구니의 동일 상품/사이즈 중복 행 목록 조회 */
SELECT CART_ID
     , CUST_NO
     , GOODS_ID
     , SIZE_ID
     , QTY
     , EXHIBITION_NO
  FROM CART
 WHERE CUST_NO = #{custNo}
   AND GOODS_ID = #{goodsId}
   AND SIZE_ID = #{sizeId}
   AND CART_GB_CD = 'C'
 ORDER BY CART_ID ASC

mapper.insert:
/* CartMapper.insertShopCart: 쇼핑몰 장바구니 등록 */
INSERT INTO CART (
       CART_GB_CD
     , CUST_NO
     , GOODS_ID
     , SIZE_ID
     , QTY
     , EXHIBITION_NO
     , REG_NO
     , UDT_NO
) VALUES (
       #{cartGbCd}
     , #{custNo}
     , #{goodsId}
     , #{sizeId}
     , #{qty}
     , #{exhibitionNo}
     , #{regNo}
     , #{udtNo}
)

mapper.update:
/* CartMapper.addShopCartQtyByGoodsIdAndSizeId: 쇼핑몰 장바구니의 동일 상품/사이즈 수량 추가 */
UPDATE CART
   SET QTY = QTY + #{qty}
     , EXHIBITION_NO = #{exhibitionNo}
     , UDT_NO = #{udtNo}
     , UDT_DT = NOW()
 WHERE CUST_NO = #{custNo}
   AND GOODS_ID = #{goodsId}
   AND SIZE_ID = #{sizeId}
   AND CART_GB_CD = 'C'

mapper.select:
/* CartMapper.getShopCartQtyByGoodsIdAndSizeId: 쇼핑몰 장바구니의 동일 상품/사이즈 현재 수량 조회 */
SELECT QTY
  FROM CART
 WHERE CUST_NO = #{custNo}
   AND GOODS_ID = #{goodsId}
   AND SIZE_ID = #{sizeId}
   AND CART_GB_CD = 'C'
 ORDER BY REG_DT DESC, CART_ID DESC
 LIMIT 1

mapper.update:
/* CartMapper.updateShopCartQtyByCartId: 쇼핑몰 장바구니 수량 수정 */
UPDATE CART
   SET QTY = #{qty}
     , UDT_NO = #{udtNo}
     , UDT_DT = NOW()
 WHERE CUST_NO = #{custNo}
   AND CART_ID = #{cartId}
   AND CART_GB_CD = 'C'

/* CartMapper.addShopCartQtyAndExhibitionByCartId: 쇼핑몰 장바구니 수량을 원자적으로 증가시키고 기획전 번호를 갱신 */
UPDATE CART
   SET QTY = QTY + #{qty}
     , EXHIBITION_NO = #{exhibitionNo}
     , UDT_NO = #{udtNo}
     , UDT_DT = NOW()
 WHERE CUST_NO = #{custNo}
   AND CART_ID = #{cartId}
   AND CART_GB_CD = 'C'

/* CartMapper.updateShopCartOptionByCartId: 쇼핑몰 장바구니 옵션(사이즈/수량) 변경 */
UPDATE CART
   SET SIZE_ID = #{targetSizeId}
     , QTY = #{targetQty}
     , UDT_NO = #{udtNo}
     , UDT_DT = NOW()
 WHERE CUST_NO = #{custNo}
   AND CART_ID = #{cartId}
   AND CART_GB_CD = 'C'

mapper.delete:
/* CartMapper.deleteShopCartByCartId: 쇼핑몰 장바구니 단건 삭제 */
DELETE
  FROM CART
 WHERE CUST_NO = #{custNo}
   AND CART_ID = #{cartId}
   AND CART_GB_CD = 'C'

/* CartMapper.deleteShopCartByGoodsIdAndSizeId: 쇼핑몰 장바구니 단건 삭제 */
DELETE
  FROM CART
 WHERE CUST_NO = #{custNo}
   AND GOODS_ID = #{goodsId}
   AND SIZE_ID = #{sizeId}
   AND CART_GB_CD = 'C'

/* CartMapper.deleteShopCartAll: 쇼핑몰 장바구니 전체 삭제 */
DELETE
  FROM CART
 WHERE CUST_NO = #{custNo}
   AND CART_GB_CD = 'C'

mapper.select:
/* CartMapper.getShopOrderCartItemList: 쇼핑몰 주문서 대상 장바구니 목록 조회 */ SELECT C.CART_ID , C.CART_GB_CD , C.CUST_NO , C.GOODS_ID , GB.BRAND_NO , BB.BRAND_NM , GB.GOODS_NM , C.SIZE_ID , C.QTY , GB.SUPPLY_AMT , GB.SALE_AMT , GS.ADD_AMT , C.EXHIBITION_NO , ( SELECT GI.IMG_PATH FROM GOODS_IMG GI WHERE GI.GOODS_ID = C.GOODS_ID ORDER BY GI.DISP_ORD ASC, GI.IMG_NO ASC LIMIT 1 ) AS IMG_PATH FROM CART C JOIN GOODS_BASE GB ON GB.GOODS_ID = C.GOODS_ID JOIN GOODS_SIZE GS ON GS.GOODS_ID = C.GOODS_ID AND GS.SIZE_ID = C.SIZE_ID LEFT JOIN BRAND_BASE BB ON BB.BRAND_NO = GB.BRAND_NO WHERE C.CUST_NO = #{custNo} AND C.CART_ID IN
#{cartId}
AND C.CART_GB_CD IN ('C', 'O') ORDER BY C.REG_DT DESC, C.CART_ID DESC

